namespace {

bool startsWithNoCaseLocal(const wchar_t* text, const wchar_t* prefix) {
    if (!text || !prefix) return false;
    while (*prefix) {
        if (!*text) return false;
        if (std::towlower(*text) != std::towlower(*prefix)) return false;
        ++text;
        ++prefix;
    }
    return true;
}

std::wstring widenLocal(const std::string& s) {
    std::wstring out;
    out.reserve(s.size());
    for (unsigned char c : s) out.push_back(static_cast<wchar_t>(c));
    return out;
}

} // namespace

ViewPlatform inferViewPlatform(const wchar_t* displayName) {
    if (!displayName) return ViewPlatform::Shared;
    if (startsWithNoCaseLocal(displayName, L"iOS ") ||
        startsWithNoCaseLocal(displayName, L"iOS -") ||
        startsWithNoCaseLocal(displayName, L"iOS Readiness")) {
        return ViewPlatform::iOS;
    }
    // This view is intentionally kept out of the macOS tab because it can contain
    // platform-mixed keyword rows and is primarily used in the iOS investigation flow.
    if (std::wcscmp(displayName, L"Investigator - Keyword Search Values") == 0) return ViewPlatform::iOS;
    return ViewPlatform::MacOS;
}

int inferViewSortPriority(const wchar_t* displayName, ViewPlatform platform) {
    const std::wstring name = displayName ? displayName : L"";
    if (platform == ViewPlatform::iOS) {
        static const wchar_t* kV1PriorityNames[] = {
            L"iOS - Investigator Overview",
            L"iOS - Investigator Super Timeline",
            L"iOS - Investigator Time Anomalies",
            L"iOS - Unified Keyword Search Surface",
            L"iOS - Spotlight Text Context Review",
            L"iOS - High-Value Spotlight Text Context",
            L"iOS - Missing From FFS Text Detail",
            L"iOS - High-Value Missing From FFS",
            L"iOS - Direct User Message Review",
            L"iOS - User-Focus Message Body Review",
            L"iOS - Spotlight Message Body Review",
            L"iOS - Spotlight Message Text Review",
            L"iOS - Spotlight Communications Investigator Review",
            L"iOS - Communications Review Records",
            L"iOS - KnowledgeC Interaction Events",
            L"iOS - Parsed App Records",
            L"iOS - Apple Messages Parsed Records",
            L"iOS - WhatsApp Parsed Records",
            L"iOS - Web History Review",
            L"iOS - Calendar Review",
            L"iOS - Contact Identity Review",
            L"iOS - Bplist/NSKeyedArchiver Detail",
            L"iOS - Store Parse Summary"
        };
        for (int i = 0; i < static_cast<int>(sizeof(kV1PriorityNames) / sizeof(kV1PriorityNames[0])); ++i) {
            if (name == kV1PriorityNames[i]) return i;
        }
        if (name.find(L"Summary") != std::wstring::npos || name.find(L"Dashboard") != std::wstring::npos) return 500;
        if (name.find(L"Parsed") != std::wstring::npos || name.find(L"Review") != std::wstring::npos) return 650;
        if (name.find(L"Timeline") != std::wstring::npos || name.find(L"Date") != std::wstring::npos) return 700;
        if (name.find(L"Inventory") != std::wstring::npos || name.find(L"Diagnostics") != std::wstring::npos) return 900;
        return 800;
    }
    return -1;
}

ViewSpec::ViewSpec(const wchar_t* display,
                   const char* table,
                   std::initializer_list<const char*> cols,
                   std::initializer_list<const char*> search,
                   const char* order,
                   ViewPlatform p,
                   int priority,
                   const wchar_t* help)
    : displayName(display),
      tableName(table),
      columns(cols),
      searchColumns(search),
      orderBy(order),
      platform(p == ViewPlatform::Auto ? inferViewPlatform(display) : p),
      sortPriority(priority >= 0 ? priority : inferViewSortPriority(display, p == ViewPlatform::Auto ? inferViewPlatform(display) : p)),
      helpText(help) {}

